import{_ as i,o as t,c as s,a3 as n}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"2. Tracking & Envoi","description":"","frontmatter":{"title":"2. Tracking & Envoi"},"headers":[],"relativePath":"publishers/dedicated-email/2-tracking-sending.md","filePath":"publishers/dedicated-email/2-tracking-sending.md"}'),a={name:"publishers/dedicated-email/2-tracking-sending.md"};function o(l,e,r,d,c,u){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="etape-2-tracking-validation-et-envoi" tabindex="-1">Étape 2 : Tracking, Validation et Envoi <a class="header-anchor" href="#etape-2-tracking-validation-et-envoi" aria-label="Permalink to &quot;Étape 2 : Tracking, Validation et Envoi&quot;">​</a></h1><p>Votre maquette est prête ? Intégrez le tracking, soumettez un BAT et gérez la diffusion.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Intégration du Tracking</h3><p>Depuis l&#39;onglet <strong>&quot;Configuration&quot;</strong> de la campagne, récupérez les deux éléments techniques :</p><ul><li><strong>👁️ Pixel d&#39;ouverture</strong> — Balise image <code>&lt;img…&gt;</code> à insérer dans le HTML de l&#39;email (avant <code>&lt;/body&gt;</code>). Indispensable pour comptabiliser les vues.</li><li><strong>🔗 Liens trackés (gtinsi.de)</strong> — Remplacez <strong>tous</strong> les liens vers l&#39;annonceur par les URLs <code>gtinsi.de</code> fournies. Indispensable pour comptabiliser les clics.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Validation BAT</h3><p>Pour valider la qualité technique, envoyez un email de test réel depuis votre routeur :</p><ul><li>Destinataire : <code>benoit+news@getinside.fr</code></li><li>Expéditeur : votre adresse d&#39;envoi habituelle</li></ul><p>Après vérification par getinside : connectez-vous à la plateforme et cliquez sur <strong>&quot;Valider la campagne&quot;</strong>. Attendez ensuite la validation côté annonceur.</p></div></div><div class="danger custom-block"><p class="custom-block-title">BAT — Email réel obligatoire</p><p>Nous ne validons <strong>jamais</strong> de BAT sous forme de capture d&#39;écran, PDF ou fichier HTML brut. L&#39;email doit être reçu sur notre boîte pour tester le responsive, le pixel et les redirections en conditions réelles.</p></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Diffusion</h3><p>Avant de router, vérifiez que les critères de segmentation du brief sont appliqués (ex : Actifs 12 mois, Genre, Géographie).</p><p>Routez l&#39;email à votre base selon le segment défini.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Renvoi aux Non-ouvreurs (RGNO)</p><p>Si un renvoi est inclus dans la commande : utilisez <strong>exactement le même email</strong> (même HTML, mêmes liens <code>gtinsi.de</code>, même pixel). Ne modifiez pas les trackers entre l&#39;envoi initial et le renvoi.</p></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Validation Finale — Action Obligatoire</h3><p>Une fois la diffusion (et le renvoi éventuel) terminée, retournez sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a> et cliquez sur <strong>&quot;Valider la diffusion&quot;</strong>.</p><p>Sans cette action, les fonds restent séquestrés et votre revenu n&#39;est pas déclenché.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Action bloquante</p><p><strong>&quot;Valider la diffusion&quot;</strong> est indispensable pour déclencher le crédit de votre revenu sur le Wallet (disponible 30 jours après la fin de campagne).</p></div>',10)])])}const v=i(a,[["render",o]]);export{g as __pageData,v as default};
